compiled.vert:
// Bond LCAO Covalent — perfil emerge de |ψ|²
uniform vec3  uPosA, uPosB;
uniform float uRadA, uRadB, uNeckMin, uNeckMax;
uniform float uTime, uScale, uBondT, uAspect;
uniform vec3  uPiOff;
uniform float uCoeffA, uCoeffB, uAntibonding;
attribute float aPhase, aT;
varying float vT, vAlpha, vNeckR;
varying float vDensity;

void main() {
    float t = position.z;
    vT = t;

    // ── Eje y base ortonormal (idéntico a VERT_HEADER) ──
    vec3 axis = uPosB - uPosA;
    float dist = length(axis);
    axis = dist > 0.001 ? axis / dist : vec3(0.0, 1.0, 0.0);
    vec3 up   = abs(axis.y) < 0.9 ? vec3(0.0, 1.0, 0.0) : vec3(1.0, 0.0, 0.0);
    vec3 tang = normalize(cross(axis, up));
    vec3 bin  = cross(axis, tang);

    float scl = (uRadA + uRadB) > dist * 0.92 ? (dist * 0.92) / (uRadA + uRadB) : 1.0;
    vec3 startP = uPosA + axis * uRadA * scl;
    float bondLen = max(dist - (uRadA + uRadB) * scl, 1.0);

    // ── LCAO: densidad electrónica ψ² a lo largo del eje ──
    // φA(t) = Gaussiana centrada en t=0 (átomo A)
    // φB(t) = Gaussiana centrada en t=1 (átomo B)
    // ψ(t) = cA·φA + cB·φB
    // densidad = |ψ|²
    //
    // α=3.5 controla el ancho de la Gaussiana — calibrado para que
    // la densidad decaiga a ~5% en los extremos del enlace.
    float alpha = 3.5;
    float phiA = exp(-alpha * t * t);               // Gaussiana en átomo A
    float phiB = exp(-alpha * (1.0 - t) * (1.0 - t)); // Gaussiana en átomo B
    float psi  = uCoeffA * phiA + uCoeffB * phiB;      // combinación lineal
    float density = psi * psi;                          // |ψ|²

    // Normalizar: densidad máxima posible = cuando ambos coeff son iguales
    // y t=0.5 → psi_max = (cA+cB) × exp(-α×0.25)
    float psiMax = (abs(uCoeffA) + abs(uCoeffB)) * exp(-alpha * 0.25);
    float normDensity = psiMax > 0.001 ? density / (psiMax * psiMax) : 0.5;
    normDensity = clamp(normDensity, 0.0, 1.0);

    // Perfil del cuello: densidad ALTA → cuello GRUESO
    // Inverso del cacahuate estético: bonding = bolillo, antibonding = cacahuate
    float neckProfile = 1.0 - normDensity;
    vNeckR = sqrt(normDensity);  // para gl_PointSize: grande donde hay densidad
    vDensity = normDensity;       // pasar al fragment para colorear

    float r = uNeckMin + (uNeckMax - uNeckMin) * neckProfile;

    // Dirección angular desde aPhase
    float ang = aPhase + uTime * 0.25;
    float tx = cos(ang) * r;
    float ty = sin(ang) * r;

    vec3 wpos = startP
              + axis * bondLen * t
              + tang * tx
              + bin  * ty
              + uPiOff;

    // Parpadeo sutil modulado por densidad — más denso parpadea menos
    float b = sin(uTime * 2.2 + aPhase * 6.28) * 0.3 * (1.0 - normDensity * 0.6) + 0.7;
    vAlpha = b;

    vec4 mvP = modelViewMatrix * vec4(wpos, 1.0);
    gl_PointSize = uScale * 0.22 * vNeckR * (0.7 + b * 0.3) * uAspect / -mvP.z;
    gl_Position = projectionMatrix * mvP;
}

compiled.frag:
// Bond LCAO Covalent — color refleja distribución de densidad
uniform vec3  uColorA, uColorB;
uniform float uBondT;
uniform float uCoeffA, uCoeffB, uAntibonding;
varying float vT, vAlpha, vNeckR;
varying float vDensity;

void main() {
    vec2  uv = gl_PointCoord - 0.5;
    float d  = dot(uv, uv);
    if (d > 0.25) discard;
    float s = 1.0 - smoothstep(0.06, 0.25, d);

    // Color: mezcla por posición, pero modulada por coeficientes
    // El átomo con mayor |coeff|² domina el color en la zona central
    float weightB = uCoeffB * uCoeffB / max(uCoeffA * uCoeffA + uCoeffB * uCoeffB, 0.001);
    vec3 col = mix(uColorA, uColorB, mix(vT, weightB, vDensity * 0.6));

    // Zona de alta densidad: tinte azul-blanco sutil (intercambio electrónico)
    col = mix(col, vec3(0.6, 0.85, 1.0), vDensity * uBondT * 0.25);

    // Antibonding: tinte rojizo en zona de nodo (cancelación)
    float nodeGlow = uAntibonding * (1.0 - vDensity) * 0.3;
    col = mix(col, vec3(1.0, 0.5, 0.3), nodeGlow);

    gl_FragColor = vec4(col, s * vAlpha * uBondT * 0.85);
}
